+
+        // Adverse events never decrease the state
+        let adverse = [DecisionEvent::SoftAnomaly, DecisionEvent::HardViolation, DecisionEvent::Timeout];
+        for &state in &all_states {
+            for &event in &adverse {
+                let t = transition(state, event);
+                assert!(
